"use strict";(self.webpackChunkajudafacitysistemas=self.webpackChunkajudafacitysistemas||[]).push([[6705],{6792:(t,a,n)=>{n.r(a),n.d(a,{assets:()=>c,contentTitle:()=>p,default:()=>m,frontMatter:()=>o,metadata:()=>i,toc:()=>l});var s=n(4848),e=n(8453);const o={title:"Como criar auto respostas e instalar o Facity BOT?",description:"Com o Facity BOT, voc\xea pode ter respostas autom\xe1ticas para pr\xe9-atender seus clientes no WhatsApp. O chatbot \xe9 especialmente \xfatil quando h\xe1 muitos clientes a ..."},p=void 0,i={id:"cadastros/como-criar-auto-respostas-e-instalar-o-facity-bot-",title:"Como criar auto respostas e instalar o Facity BOT?",description:"Com o Facity BOT, voc\xea pode ter respostas autom\xe1ticas para pr\xe9-atender seus clientes no WhatsApp. O chatbot \xe9 especialmente \xfatil quando h\xe1 muitos clientes a ...",source:"@site/docs/cadastros/como-criar-auto-respostas-e-instalar-o-facity-bot-.mdx",sourceDirName:"cadastros",slug:"/cadastros/como-criar-auto-respostas-e-instalar-o-facity-bot-",permalink:"/docs/cadastros/como-criar-auto-respostas-e-instalar-o-facity-bot-",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{title:"Como criar auto respostas e instalar o Facity BOT?",description:"Com o Facity BOT, voc\xea pode ter respostas autom\xe1ticas para pr\xe9-atender seus clientes no WhatsApp. O chatbot \xe9 especialmente \xfatil quando h\xe1 muitos clientes a ..."},sidebar:"tutorialSidebar",previous:{title:"Como configurar tempo estimado?",permalink:"/docs/cadastros/como-configurar-tempo-estimado-"},next:{title:"Como criar chave do Google Maps e configurar taxa de entrega (Km)?",permalink:"/docs/cadastros/como-criar-chave-do-google-maps-e-configurar-taxa-de-entrega--km--"}},c={},l=[];function r(t){return(0,s.jsx)(s.Fragment,{children:(0,s.jsx)(s.Fragment,{children:(0,s.jsx)("div",{dangerouslySetInnerHTML:{__html:'\n  \n<p class="has-small-font-size">Com o <strong>Facity BOT</strong>, voc\xea pode ter respostas autom\xe1ticas para pr\xe9-atender seus clientes no <strong>WhatsApp</strong>. O <strong>chatbot</strong> \xe9 especialmente \xfatil quando h\xe1 muitos clientes a serem atendidos, pois pode responder simultaneamente sem que voc\xea precise atend\xea-los um por um.</p>\n\n\n\n<p class="has-small-font-size">Para come\xe7ar a usar o<strong> chatbot</strong>, voc\xea precisa instalar uma extens\xe3o no seu navegador. Siga estes passos:</p>\n\n\n\n<ol class="wp-block-list has-small-font-size">\n<li>Abra o link <strong><a href="https://chrome.google.com/webstore/detail/facity-bot/gjnhbgneccjnjjgpnbbclnmphgpgdnnf/related?hl=pt-BR&amp;authuser=0">https://chrome.google.com/webstore/detail/facity-bot/gjnhbgneccjnjjgpnbbclnmphgpgdnnf/related?hl=pt-BR&amp;authuser=0</a> </strong>no seu navegador.</li>\n</ol>\n\n\n\n<figure class="wp-block-image size-full is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="790" height="429" src="https://manual.facity.com.br/wp-content/uploads/2022/10/botq.png" alt="" class="wp-image-1957" style="width:973px;height:574px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/botq.png 790w, https://manual.facity.com.br/wp-content/uploads/2022/10/botq-300x163.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/botq-768x417.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/botq-720x391.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">   2. Clique no bot\xe3o azul <strong>&#8220;Adicionar ao Chrome&#8221;</strong>.</p>\n\n\n\n<p class="has-small-font-size">   3. Clique em <strong>&#8220;Adicionar extens\xe3o&#8221;</strong>.</p>\n\n\n\n<figure class="wp-block-image size-full"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="801" height="476" src="https://manual.facity.com.br/wp-content/uploads/2022/10/bot2.png" alt="" class="wp-image-1958" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/bot2.png 801w, https://manual.facity.com.br/wp-content/uploads/2022/10/bot2-300x178.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/bot2-768x456.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/bot2-720x428.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">Agora, abra o <strong>WhatsApp</strong> Web para continuar a instala\xe7\xe3o do<strong> BOT</strong>. Uma tela de cadastro aparecer\xe1. Preencha com as seguintes informa\xe7\xf5es:</p>\n\n\n\n<ul class="wp-block-list has-small-font-size">\n<li><strong>ONLINE</strong>: Deixe como est\xe1, a menos que voc\xea possua a vers\xe3o offline do sistema.</li>\n\n\n\n<li><strong>Nome da sua empresa</strong> (<em>em letras min\xfasculas</em>).</li>\n\n\n\n<li><strong>Usu\xe1rio</strong>.</li>\n\n\n\n<li><strong>Senha</strong>.</li>\n</ul>\n\n\n\n<figure class="wp-block-image size-full is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="931" height="590" src="https://manual.facity.com.br/wp-content/uploads/2022/10/instalarbot3.png" alt="" class="wp-image-358" style="width:1004px;height:636px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/instalarbot3.png 931w, https://manual.facity.com.br/wp-content/uploads/2022/10/instalarbot3-300x190.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/instalarbot3-768x487.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/instalarbot3-720x456.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">Quando terminar de preencher as informa\xe7\xf5es, clique em <strong>&#8220;Fazer Login&#8221;</strong>. O <strong>BOT</strong> ficar\xe1 dispon\xedvel no sistema com a cor <strong>vermelha (offline)</strong> ou <strong>verde (online)</strong>.</p>\n\n\n\n<figure class="wp-block-image size-large is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="91" src="https://manual.facity.com.br/wp-content/uploads/2022/10/image-41-1024x91.png" alt="" class="wp-image-360" style="width:1020px;height:91px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/image-41-1024x91.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-41-300x27.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-41-768x69.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-41-720x64.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-41.png 1277w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">Com o <strong>BOT </strong>instalado, voc\xea pode come\xe7ar a criar suas auto respostas. Siga estes passos:</p>\n\n\n\n<ol class="wp-block-list has-small-font-size">\n<li>Abra o <strong>Facity Controle</strong> no seu computador.</li>\n\n\n\n<li>Insira o <strong>nome da sua empresa</strong>, <strong>login</strong> e <strong>senha</strong> (<em>em letras min\xfasculas</em>).</li>\n</ol>\n\n\n\n<p></p>\n\n\n\n<figure class="wp-block-image size-full is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="900" height="547" src="https://manual.facity.com.br/wp-content/uploads/2022/10/image-39.png" alt="" class="wp-image-339" style="width:1007px;height:613px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/image-39.png 900w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-39-300x182.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-39-768x467.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-39-720x438.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">  3. Clique em <strong>&#8220;Marketing&#8221; </strong>no menu lateral esquerdo.</p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="531" src="https://manual.facity.com.br/wp-content/uploads/2022/10/image-40-1024x531.png" alt="" class="wp-image-340" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/image-40-1024x531.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-40-300x156.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-40-768x399.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-40-720x374.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/image-40.png 1108w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">   4. Selecione <strong>&#8220;Auto Resposta&#8221;.</strong></p>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="515" src="https://manual.facity.com.br/wp-content/uploads/2022/10/autoresosta-1024x515.png" alt="" class="wp-image-341" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/autoresosta-1024x515.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/autoresosta-300x151.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/autoresosta-768x386.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/autoresosta-720x362.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/autoresosta.png 1134w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">  5. Para criar uma nova auto resposta, clique no <strong>\xedcone azul</strong>. Para editar uma auto resposta existente, clique no <strong>\xedcone verde</strong>. Para deletar uma auto resposta, clique no <strong>\xedcone vermelho</strong>.</p>\n\n\n\n<p class="has-small-font-size"> 6. Crie as <strong>sub-respostas</strong> a partir da primeira mensagem para que a sequ\xeancia seja seguida corretamente.</p>\n\n\n\n<p class="has-small-font-size"><em>Toda sub resposta ela tem que ser criada a partir da primeira mensagem pra ela seguir em um</em>a sequ\xeancia igual </p>\n\n\n\n<p></p>\n\n\n\n<p class="has-small-font-size"><strong>Veja alguns exemplos de auto respostas abaixo:</strong></p>\n\n\n\n<figure class="wp-block-image size-large is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1047" height="553" src="https://manual.facity.com.br/wp-content/uploads/2022/10/1-1024x541.png" alt="" class="wp-image-346" style="width:1012px;height:535px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/1-1024x541.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/1-300x158.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/1-768x406.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/1-720x380.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/1.png 1047w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-large is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="575" src="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-173501-1-1024x575.png" alt="" class="wp-image-349" style="width:1014px;height:569px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-173501-1-1024x575.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-173501-1-300x168.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-173501-1-768x431.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-173501-1-720x404.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-173501-1.png 1042w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-full is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1009" height="630" src="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174112-1.png" alt="" class="wp-image-350" style="width:1014px;height:633px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174112-1.png 1009w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174112-1-300x187.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174112-1-768x480.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174112-1-720x450.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-full"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1016" height="638" src="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174610.png" alt="" class="wp-image-351" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174610.png 1016w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174610-300x188.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174610-768x482.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-174610-720x452.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-full is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="980" height="629" src="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180101.png" alt="" class="wp-image-352" style="width:1020px;height:655px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180101.png 980w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180101-300x193.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180101-768x493.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180101-720x462.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="577" src="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180417-1024x577.png" alt="" class="wp-image-353" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180417-1024x577.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180417-300x169.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180417-768x433.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180417-720x406.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-180417.png 1162w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<ul class="wp-block-list has-small-font-size">\n<li>Um exemplo de <strong>auto respostas </strong>completo:</li>\n</ul>\n\n\n\n<figure class="wp-block-image size-large"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="1024" height="618" src="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-171513-1024x618.png" alt="" class="wp-image-354" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-171513-1024x618.png 1024w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-171513-300x181.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-171513-768x463.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-171513-720x434.png 720w, https://manual.facity.com.br/wp-content/uploads/2022/10/Captura-de-tela-2022-10-25-171513.png 1026w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p></p>\n\n\n\n<figure class="wp-block-image size-full is-resized"><img style="max-width: 100%; height: auto;" loading="lazy" decoding="async" width="908" height="561" src="https://manual.facity.com.br/wp-content/uploads/2022/10/26_10_2022-12_47_56.png" alt="" class="wp-image-364" style="width:1038px;height:641px" srcset="https://manual.facity.com.br/wp-content/uploads/2022/10/26_10_2022-12_47_56.png 908w, https://manual.facity.com.br/wp-content/uploads/2022/10/26_10_2022-12_47_56-300x185.png 300w, https://manual.facity.com.br/wp-content/uploads/2022/10/26_10_2022-12_47_56-768x475.png 768w, https://manual.facity.com.br/wp-content/uploads/2022/10/26_10_2022-12_47_56-720x445.png 720w" sizes="(min-width: 960px) 75vw, 100vw" /></figure>\n\n\n\n<p class="has-small-font-size">N\xe3o se esque\xe7a de<strong> salvar </strong>todo o processo no final para que suas auto respostas fiquem dispon\xedveis no sistema. Com esses passos simples, voc\xea pode instalar o <strong>Facity BOT</strong> e criar suas pr\xf3prias auto respostas para o <strong>WhatsApp</strong>.</p>\n\n'}})})})}function m(t={}){const{wrapper:a}={...(0,e.R)(),...t.components};return a?(0,s.jsx)(a,{...t,children:(0,s.jsx)(r,{...t})}):r()}},8453:(t,a,n)=>{n.d(a,{R:()=>p,x:()=>i});var s=n(6540);const e={},o=s.createContext(e);function p(t){const a=s.useContext(o);return s.useMemo((function(){return"function"==typeof t?t(a):{...a,...t}}),[a,t])}function i(t){let a;return a=t.disableParentContext?"function"==typeof t.components?t.components(e):t.components||e:p(t.components),s.createElement(o.Provider,{value:a},t.children)}}}]);